 917→.editor-tokenize-selector { color: #22863a; }
 918→.editor-tokenize-attr { color: #6f42c1; }
 919→.editor-tokenize-class-name { color: #6f42c1; }
 920→.editor-tokenize-tag { color: #22863a; }
 921→.editor-tokenize-boolean { color: #005cc5; }
 922→.editor-tokenize-builtin { color: #005cc5; }
 923→.editor-tokenize-constant { color: #005cc5; }
 924→.editor-tokenize-important { color: #d73a49; font-weight: bold; }
 925→.editor-tokenize-regex { color: #032f62; }
 926→.editor-tokenize-atrule { color: #d73a49; }
 927→.editor-tokenize-char { color: #032f62; }
